<?php namespace App\Repositories\Student;use App\Repositories\BaseRepository;use App\Models\Student\StudentAward;use Illuminate\Database\Eloquent\Collection;use Illuminate\Pagination\LengthAwarePaginator;class StudentAwardRepository extends BaseRepository{    public function __construct(StudentAward $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByStudent(int $studentId): Collection    {        return $this->findByField('student_id', $studentId);    }    public function findByAwardType(string $awardType): Collection    {        return $this->findByField('award_type', $awardType);    }    public function getByAcademicYear(int $academicYearId): Collection    {        return $this->findByField('academic_year_id', $academicYearId);    }    public function getByDateRange(string $startDate, string $endDate): Collection    {        return $this->query()->whereBetween('award_date', [$startDate, $endDate])->get();    }    public function getRecentAwards(int $limit = 10): Collection    {        return $this->query()->orderBy('award_date', 'desc')->limit($limit)->get();    }    public function countByType(): Collection    {        return $this->query()->selectRaw('award_type, COUNT(*) as total')->groupBy('award_type')->get();    }    public function searchAwards(string $keyword): Collection    {        return $this->query()->where('award_name', 'like', "%{$keyword}%")->orWhere('description', 'like', "%{$keyword}%")->get();    }}